const input = $input.first().json;
const tokens = $('account tokens').first().json;
const ports = $('account port').first().json;
const rawAccount = $input.first().json.account;
const indexes = String(rawAccount)
  .split(',')
  .map(s => parseInt(s.trim(), 10))
  .filter(n => !isNaN(n));

const result = [];

for (const i of indexes) {
  const key = `v${i}`;
  const value = input[key];

  const keyv = `Midjourny image ${i} 1,2,3,4`;
  const valuev = input[keyv];

  const imageGeneratedKey = `U2 ${i}`;
  const imageGeneratedValue = input[imageGeneratedKey];

  const token = tokens[`account ${i}`] || "";
  const port = ports[`account ${i}`] || "";
  if (
    value &&
    value.trim() !== '' &&
    !(typeof imageGeneratedValue === 'string' &&
      imageGeneratedValue.startsWith("https://cdn.discordapp.com/attachments/"))
  ) {
    result.push({
      v: value,
      vchoose: valuev,
      index: i,
      token: token,
      port: port
    });
  }
}

return [
  {
    json: {
      vdata: result
    }
  }
];

const input = $input.first().json;

// Get account list from the current sheet row
const rawAccount = $('Loop Over Items1').item.json['account'];
const indexes = String(rawAccount)
  .split(',')
  .map(s => parseInt(s.trim(), 10))
  .filter(n => !isNaN(n));

const promptsData = $('promps').first().json;
const Data = $('set place id').first().json;

const result = [];

const templateNumber = input.templite_combo_number;
const accounts = input.accounts || [];

for (const accObj of accounts) {
  const acc = accObj.account;

  // Only process accounts in the per-row account list
  if (!indexes.includes(acc)) continue;

  const promptKey = `promp accont ${acc}`;
  const promptSet = promptsData[promptKey];

  if (!promptSet) {
    throw new Error(`No prompts found for account index ${acc}`);
  }

  const placeKey = `account ${acc}`;
  const placeSet = Data[placeKey];

  if (!placeSet) {
    throw new Error(`No place config found for account ${acc}`);
  }

  const randomNum = Math.floor(Math.random() * 4) + 1;

  result.push({
    U1: accObj.image1_url || "",
    U2: accObj.image2_url || "",
    index: acc,
    keyword: input.KEYWORDS || "",
    row_number: input.row_number || "",
    image_url: accObj.image1_url || "",
    templite: templateNumber || "",
    combo_label: accObj.combo_label || "",
    state: input.state || "",
    link: input.link || "",
    title: promptSet[`title ${randomNum}`],
    accountapi: placeSet["apikey"],
    template: placeSet[`template${templateNumber}`],
    description: promptSet[`description ${randomNum}`],
    tagline: promptSet[`tagline ${randomNum}`],
    board: promptSet[`board ${randomNum}`],
  });
}

return [
  {
    json: {
      vdata: result,
    },
  },
];

const items = $input.all();
const outputItems = [];

for (const item of items) {
  const data = item.json;

  const rawTemplite = String(data.templite ?? '').trim();
  if (!rawTemplite) continue;

  const selectedIndexes = rawTemplite
    .split(',')
    .map(s => parseInt(s.trim(), 10))
    .filter(n => n >= 1 && n <= 6);

  if (selectedIndexes.length === 0) continue;

  // Parse account list from the row
  const rawAccount = String(data.account ?? '').trim();
  const allowedAccounts = rawAccount
    .split(',')
    .map(s => parseInt(s.trim(), 10))
    .filter(n => !isNaN(n));

  for (const idx of selectedIndexes) {
    const accountCombos = [];

    for (let acc = 1; acc <= 10; acc++) {

      // Only process accounts listed in the row's "account" column
      if (!allowedAccounts.includes(acc)) continue;

      const images = [];

      for (const prefix of ['U1', 'U2', 'U3', 'U4']) {
        const key = `${prefix} ${acc}`;
        if (data[key] && data[key].trim() !== '') {
          images.push({ label: key, url: data[key] });
        }
      }

      if (images.length < 2) continue;

      const allCombos = [];
      for (let i = 0; i < images.length; i++) {
        for (let j = i + 1; j < images.length; j++) {
          allCombos.push([images[i], images[j]]);
        }
      }

      const combo = allCombos[idx - 1];
      if (!combo) continue;

      const [img1, img2] = combo;
      accountCombos.push({
        account: acc,
        combo_label: `${img1.label} + ${img2.label}`,
        image1_label: img1.label,
        image1_url: img1.url,
        image2_label: img2.label,
        image2_url: img2.url,
      });
    }

    if (accountCombos.length === 0) continue;

    outputItems.push({
      json: {
        row_number: data.row_number,
        KEYWORDS: data.KEYWORDS,
        link: data.link,
        Date: data.Date,
        account: data.account,       // ← pass through for splite images u
        state: data.state,           // ← pass through
        templite_combo_number: idx,
        accounts: accountCombos,
      }
    });
  }
}

return outputItems;
